import { api } from 'lwc';
import LightningOverlay from 'lightning/overlay';
export default class InfoOverlay extends LightningOverlay {
    @api
    message = '';
    connectedCallback() {
        super.connectedCallback();
        const close = this.close.bind(this);
        this.source.addEventListener('mouseleave', close);
        this.source.addEventListener('focusout', close);
    }
    renderedCallback() {
        this.source.ariaDescribedByElements = [this.refs.tooltip];
    }
}
